// Token endpoint
app.post('/oauth/token', async (req, res) => {
  const { grant_type } = req.body;

  // Extract client credentials from Authorization header or body
  let clientId, clientSecret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const colonIndex = decoded.indexOf(':');
    if (colonIndex === -1) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client authentication' });
    }
    clientId = decodeURIComponent(decoded.slice(0, colonIndex));
    clientSecret = decodeURIComponent(decoded.slice(colonIndex + 1));
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId || !clientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  const client = await authenticateClient(clientId, clientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  if (!client.grantTypes.includes(grant_type)) {
    return res.status(400).json({ error: 'unauthorized_client', error_description: 'Grant type not allowed for this client' });
  }

  switch (grant_type) {
    case 'password':
      return handlePasswordGrant(req, res, client);
    case 'refresh_token':
      return handleRefreshTokenGrant(req, res, client);
    default:
      return res.status(400).json({ error: 'unsupported_grant_type', error_description: `Grant type '${grant_type}' is not supported` });
  }
});

async function handlePasswordGrant(req, res, client) {
  const { username, password, scope } = req.body;

  if (!username || !password) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Username and password are required' });
  }

  const userResult = await authenticateUser(username, password);
  if (!userResult) {
    return res.status(401).json({ error: 'invalid_grant', error_description: 'Invalid username or password' });
  }
  if (userResult.error) {
    return res.status(403).json({ error: userResult.error, error_description: userResult.error_description });
  }

  const user = userResult;

  // Validate requested scopes
  const requestedScopes = scope ? scope.split(' ').filter(s => s) : ['read'];
  const validScopes = requestedScopes.filter(s => client.scopes.includes(s));
  if (validScopes.length === 0) {
    return res.status(400).json({ error: 'invalid_scope', error_description: 'No valid scopes requested' });
  }

  // Generate tokens
  const accessToken = generateAccessToken(user, client, validScopes);
  const refreshToken = generateSecureToken();
  const family = generateTokenFamily();

  await storeRefreshToken(refreshToken, {
    userId: user.userId,
    clientId: client.clientId,
    scopes: validScopes,
    family,
    chainLength: 0,
  });

  // Set cache control headers
  res.set({
    'Cache-Control': 'no-store',
    'Pragma': 'no-cache',
  });

  return res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900, // 15 minutes in seconds
    refresh_token: refreshToken,
    scope: validScopes.join(' '),
  });
}

async function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Refresh token is required' });
  }

  const result = await validateAndRotateRefreshToken(refresh_token, client.clientId);

  if (result.error) {
    return res.status(400).json({ error: result.error, error_description: result.error_description });
  }

  const tokenData = result.data;

  // Verify user still exists and is active
  let user = null;
  for (const [, u] of users) {
    if (u.userId === tokenData.userId && u.active) {
      user = u;
      break;
    }
  }

  if (!user) {
    await revokeTokenFamily(tokenData.family);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'User account is no longer active' });
  }

  // Handle scope narrowing (can only narrow, not widen)
  let grantedScopes = tokenData.scopes;
  if (scope) {
    const requestedScopes = scope.split(' ').filter(s => s);
    grantedScopes = requestedScopes.filter(s => tokenData.scopes.includes(s));
    if (grantedScopes.length === 0) {
      return res.status(400).json({ error: 'invalid_scope', error_description: 'Requested scopes exceed original grant' });
    }
  }

  // Generate new access token
  const accessToken = generateAccessToken(user, client, grantedScopes);

  const responseBody = {
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    scope: grantedScopes.join(' '),
  };

  // If within grace period, don't issue new refresh token
  if (!result.gracePeriod) {
    // Rotate: issue new refresh token
    const newRefreshToken = generateSecureToken();

    await storeRefreshToken(newRefreshToken, {
      userId: tokenData.userId,
      clientId: tokenData.clientId,
      scopes: tokenData.scopes, // Preserve original scopes for the refresh token
      family: tokenData.family,
      chainLength: (tokenData.chainLength || 0) + 1,
    });

    responseBody.refresh_token = newRefreshToken;
  }

  res.set({
    'Cache-Control': 'no-store',
    'Pragma': 'no-cache',
  });

  return res.json(responseBody);
}

