app.post('/oauth/introspect', tokenRateLimiter, async (req, res) => {
  const { token } = req.body;

  // Authenticate client
  let clientId, clientSecret;
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const colonIndex = decoded.indexOf(':');
    if (colonIndex !== -1) {
      clientId = decodeURIComponent(decoded.slice(0, colonIndex));
      clientSecret = decodeURIComponent(decoded.slice(colonIndex + 1));
    }
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId || !clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const client = await authenticateClient(clientId, clientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.json({ active: false });
  }

  // Try as JWT access token
  try {
    const decoded = jwt.verify(token, config.accessTokenSecret, {
      issuer: 'oauth-server',
      audience: client.clientId,
    });

    return res.json({
      active: true,
      sub: decoded.sub,
      client_id: decoded.client_id,
      scope: decoded.scope,
      token_type: 'Bearer',
      exp: decoded.exp,
      iat: decoded.iat,
      iss: decoded.iss,
    });
  } catch {
    // Not a valid access token
  }

  // Try as refresh token
  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
  const key = `refresh_token:${tokenHash}`;
  const dataStr = await redis.get(key);

  if (dataStr) {
    const data = JSON.parse(dataStr);
    if (data.clientId === client.clientId && !data.used) {
      return res.json({
        active: true,
        sub: data.userId,
        client_id: data.clientId,
        scope: data.scopes.join(' '),
        token_type: 'refresh_token',
      });
    }
  }

  return res.json({ active: false });
});

